import type {
  AccessorFnColumnDef,
  AccessorKeyColumnDef,
  DisplayColumnDef,
  GroupColumnDef,
} from './types.js';
import type { DataTableRowData } from '../../public.api.js';

/**
 * Makes sure that a columnDef is a groupColumnDef
 * @internal
 */
export function isGroupColumnDef<
  TData extends DataTableRowData,
  TValue = unknown,
>(
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  columnDef: any,
): columnDef is GroupColumnDef<TData, TValue> {
  return (
    typeof columnDef === 'object' &&
    columnDef.columns !== undefined &&
    Array.isArray(columnDef.columns)
  );
}

/**
 * Makes sure that a columnDef is a displayColumnDef
 * @internal
 */
export function isDisplayColumnDef<
  TData extends DataTableRowData,
  TValue = unknown,
>(
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  columnDef: any,
): columnDef is DisplayColumnDef<TData, TValue> {
  return (
    typeof columnDef === 'object' &&
    columnDef.columns === undefined &&
    !Array.isArray(columnDef.columns)
  );
}

/**
 * Makes sure that the columnDef is a AccessorKeyColumnDef
 * @internal
 */
export function isAccessorKeyColumnDef<
  TData extends DataTableRowData,
  TValue = unknown,
>(
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  columnDef: any,
): columnDef is AccessorKeyColumnDef<TData, TValue> {
  return (
    typeof columnDef === 'object' &&
    columnDef.accessorKey !== undefined &&
    typeof columnDef.accessorKey === 'string'
  );
}

/**
 * Makes sure that the columnDef is a AccessorFnColumnDef
 * @internal
 */
export function isAccessorFnColumnDef<
  TData extends DataTableRowData,
  TValue = unknown,
>(
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  columnDef: any,
): columnDef is AccessorFnColumnDef<TData, TValue> {
  return (
    typeof columnDef === 'object' &&
    columnDef.accessorFn !== undefined &&
    typeof columnDef.accessorFn === 'function'
  );
}
